var wall = new FilteredElementCollector(doc)
    .OfClass(typeof(Wall))
    .Cast<Wall>()
    .FirstOrDefault();
var lengthFt = (wall?.Location as LocationCurve)?.Curve.Length ?? 0;
var lengthMm = UnitUtils.ConvertFromInternalUnits(lengthFt, UnitTypeId.Millimeters);
return new { wallId = wall?.Id.IntegerValue, lengthFt, lengthMm };

var wall = new FilteredElementCollector(doc)
    .OfClass(typeof(Wall))
    .Cast<Wall>()
    .FirstOrDefault();
return wall == null
    ? new { found = false }
    : new { found = true, id = wall.Id.IntegerValue, name = wall.Name };

