var instance = new FilteredElementCollector(doc)
    .OfClass(typeof(FamilyInstance))
    .Cast<FamilyInstance>()
    .FirstOrDefault();
var symbol = instance?.Symbol;
return new
{
    instanceId = instance?.Id.IntegerValue,
    typeName = symbol?.Name,
    familyName = symbol?.Family?.Name
};

var door = new FilteredElementCollector(doc)
    .OfCategory(BuiltInCategory.OST_Doors)
    .WhereElementIsNotElementType()
    .Cast<FamilyInstance>()
    .FirstOrDefault();
var widthParam = door?.get_Parameter(BuiltInParameter.DOOR_WIDTH)
    ?? door?.Symbol?.get_Parameter(BuiltInParameter.DOOR_WIDTH);
var widthFt = widthParam?.AsDouble() ?? 0;
var widthMm = UnitUtils.ConvertFromInternalUnits(widthFt, UnitTypeId.Millimeters);
return new { doorId = door?.Id.IntegerValue, widthFt, widthMm };
